// ── BEZIER HELPERS ──────────────────────────────────────────────────────────
function cubicBezier(t, p0, p1, p2, p3) {
  const mt = 1 - t;
  return {
    x: mt*mt*mt*p0.x + 3*mt*mt*t*p1.x + 3*mt*t*t*p2.x + t*t*t*p3.x,
    y: mt*mt*mt*p0.y + 3*mt*mt*t*p1.y + 3*mt*t*t*p2.y + t*t*t*p3.y,
  };
}
function cubicBezierAngle(t, p0, p1, p2, p3) {
  const mt = 1 - t;
  const dx = 3*(mt*mt*(p1.x-p0.x) + 2*mt*t*(p2.x-p1.x) + t*t*(p3.x-p2.x));
  const dy = 3*(mt*mt*(p1.y-p0.y) + 2*mt*t*(p2.y-p1.y) + t*t*(p3.y-p2.y));
  return Math.atan2(dy, dx) * 180 / Math.PI;
}

// ── LEI DRAPE PREVIEW ───────────────────────────────────────────────────────
function LeiDrapePreview({ colors, hasMoney, billDenom, billCount, hasBeads, beadAmount, hasFauxLeather, leatherAmount, leatherColor, themes, customText }) {
  const displayColors = colors.length > 0 ? colors : [{ hex: "#D4B06A" }, { hex: "#8B5E1A" }];
  const W = 340, H = 195;
  const p0={x:28,y:16}, p1={x:28,y:188}, p2={x:312,y:188}, p3={x:312,y:16};

  const PETAL_COUNT = 34;
  const petals = Array.from({length: PETAL_COUNT}, (_, i) => {
    const t = i / (PETAL_COUNT - 1);
    const pos = cubicBezier(t, p0, p1, p2, p3);
    const angle = cubicBezierAngle(t, p0, p1, p2, p3);
    return { ...pos, angle, color: displayColors[i % displayColors.length].hex, t };
  });

  const beadStep = beadAmount === "large" ? 2 : beadAmount === "medium" ? 4 : 8;

  // Leather fringe: pick every Nth petal, push outward from lei center
  const leatherStep = leatherAmount === "large" ? 3 : 6;
  const LEI_CX = 170, LEI_CY = 95; // approximate visual center of the drape
  const FRINGE_OFFSET = 18; // how far the tab sticks out from the petal
  const lColor = leatherColor === "black" ? "#1a1a1a" : "#7B3F10";
  const lHighlight = leatherColor === "black" ? "rgba(255,255,255,0.12)" : "rgba(255,200,130,0.3)";
  const lStroke = leatherColor === "black" ? "#000" : "#4a2008";

  const leatherTabs = hasFauxLeather
    ? petals.filter((_, i) => i % leatherStep === 1).map(p => {
        // Outward normal: direction from lei center to this petal point
        const dx = p.x - LEI_CX;
        const dy = p.y - LEI_CY;
        const len = Math.sqrt(dx * dx + dy * dy) || 1;
        const nx = dx / len;
        const ny = dy / len;
        // Position tab outward from the petal
        const tx = p.x + nx * FRINGE_OFFSET;
        const ty = p.y + ny * FRINGE_OFFSET;
        // Rotation angle to face outward
        const rot = Math.atan2(ny, nx) * 180 / Math.PI + 90;
        return { x: tx, y: ty, rot };
      })
    : [];

  const moneyCount = Math.min(billCount || 0, 7);
  const moneyPositions = hasMoney && moneyCount > 0
    ? Array.from({length: moneyCount}, (_, i) => {
        const t = 0.22 + (i / Math.max(moneyCount - 1, 1)) * 0.56;
        const pos = cubicBezier(t, p0, p1, p2, p3);
        const angle = cubicBezierAngle(t, p0, p1, p2, p3);
        return {...pos, angle};
      })
    : [];

  const bottomCenter = cubicBezier(0.5, p0, p1, p2, p3);
  const activeThemes = Array.isArray(themes) ? themes : (themes ? [themes] : []);
  const emojis = activeThemes.slice(0, 3).map(v => THEME_OPTIONS.find(o => o.value === v)?.emoji).filter(Boolean);
  const emojiStr = emojis.join(" ");
  const text = (customText || "").trim().toUpperCase();

  return (
    <div>
      <svg width="100%" viewBox={`-5 -5 ${W+10} ${H+54}`} style={{maxWidth:"340px",display:"block",margin:"0 auto",filter:"drop-shadow(0 4px 18px rgba(0,0,0,0.12))"}}>
        <defs>
          <filter id="ps"><feDropShadow dx="0" dy="1" stdDeviation="2" floodOpacity="0.18"/></filter>
          <filter id="ls"><feDropShadow dx="0" dy="2" stdDeviation="2.5" floodOpacity="0.35"/></filter>
        </defs>
        {/* Shoulder silhouette hint */}
        <path d="M 0,16 Q 30,10 80,14 L 80,22 Q 30,18 0,24 Z" fill="rgba(200,170,120,0.13)" />
        <path d="M 340,16 Q 310,10 260,14 L 260,22 Q 310,18 340,24 Z" fill="rgba(200,170,120,0.13)" />
        <ellipse cx="170" cy="-2" rx="44" ry="12" fill="rgba(200,170,120,0.1)" />
        {/* Cord */}
        <path d={`M ${p0.x},${p0.y} C ${p1.x},${p1.y} ${p2.x},${p2.y} ${p3.x},${p3.y}`}
          fill="none" stroke="rgba(165,130,55,0.45)" strokeWidth="12" strokeLinecap="round" />
        {/* Petals */}
        {petals.map((p, i) => (
          <g key={i} transform={`translate(${p.x},${p.y}) rotate(${p.angle+90})`} filter="url(#ps)">
            <ellipse rx="9" ry="14" fill={p.color} stroke="rgba(255,255,255,0.5)" strokeWidth="0.6" opacity="0.96"/>
            <ellipse rx="4" ry="7" cy="-2" fill="rgba(255,255,255,0.2)"/>
          </g>
        ))}
        {/* Beads — on top of petals */}
        {hasBeads && petals.filter((_,i) => i % beadStep === Math.floor(beadStep/2)).map((p, i) => (
          <circle key={i} cx={p.x} cy={p.y} r="5.5"
            fill={displayColors[i % displayColors.length]?.hex || "#aaa"}
            stroke="rgba(255,255,255,0.85)" strokeWidth="1.5" filter="url(#ps)"/>
        ))}
        {/* Money bills */}
        {moneyPositions.map((mp, i) => (
          <g key={i} transform={`translate(${mp.x},${mp.y}) rotate(${mp.angle+90})`}>
            <rect x="-12" y="-8" width="24" height="16" rx="2.5" fill="#85BB65" stroke="#3e7a28" strokeWidth="0.9"/>
            <text textAnchor="middle" dy="5.5" fontSize="9.5" fill="#1a3d08" fontWeight="800" fontFamily="monospace">${billDenom}</text>
          </g>
        ))}
        {/* ── FAUX LEATHER FRINGE — rendered ON TOP, sticking outward ── */}
        {leatherTabs.map((lt, i) => (
          <g key={i} transform={`translate(${lt.x},${lt.y}) rotate(${lt.rot})`} filter="url(#ls)">
            {/* Main leather tab body */}
            <rect x="-5.5" y="-14" width="11" height="20" rx="2" fill={lColor} stroke={lStroke} strokeWidth="0.7"/>
            {/* Pointed tip */}
            <polygon points="0,-16 -5.5,-10 5.5,-10" fill={lColor} stroke={lStroke} strokeWidth="0.5"/>
            {/* Stitching highlight */}
            <rect x="-3" y="-12" width="6" height="3" rx="1" fill={lHighlight}/>
            {/* Stitch dots */}
            <circle cx="0" cy="2" r="1" fill={lHighlight}/>
            <circle cx="0" cy="5" r="1" fill={lHighlight}/>
          </g>
        ))}
        {/* Bottom decorations */}
        {emojiStr && (
          <text x={bottomCenter.x} y={bottomCenter.y + 4} textAnchor="middle" fontSize="22" dominantBaseline="middle">{emojiStr}</text>
        )}
        {text && (
          <text x={bottomCenter.x} y={bottomCenter.y + (emojiStr ? 26 : 14)} textAnchor="middle"
            fontSize="10.5" fontWeight="800" fontFamily="'Georgia', serif"
            fill="#3d1500" letterSpacing="2.5" opacity="0.9">{text}</text>
        )}
      </svg>
      <p style={{textAlign:"center",fontSize:"11px",color:"#bbb",fontStyle:"italic",margin:"6px 0 0",fontFamily:"sans-serif",letterSpacing:"0.5px"}}>
        ✦ Simplified preview — for design reference only ✦
      </p>
    </div>
  );
}

// ── PRICING CARD ────────────────────────────────────────────────────────────
function PricingCard({ items, total, basePrice }) {
  return (
    <div style={{background:"white",borderRadius:"16px",padding:"20px",boxShadow:"0 2px 16px rgba(0,0,0,0.07)",fontSize:"13px",fontFamily:"sans-serif"}}>
      <h4 style={{margin:"0 0 12px",color:"#5a3000",fontSize:"14px",fontWeight:"700",letterSpacing:"0.5px"}}>💰 Estimated Total</h4>
      <div style={{borderTop:"1px dashed #e5c88a",paddingTop:"10px"}}>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:"6px",color:"#7a5520"}}>
          <span>Base Lei</span><span>${basePrice}.00</span>
        </div>
        {items.map((item, i) => (
          <div key={i} style={{display:"flex",justifyContent:"space-between",marginBottom:"6px",color:"#7a5520"}}>
            <span>{item.label}</span><span>+${item.cost.toFixed(2)}</span>
          </div>
        ))}
      </div>
      <div style={{borderTop:"2px solid #e5c88a",marginTop:"8px",paddingTop:"8px",display:"flex",justifyContent:"space-between",fontWeight:"800",fontSize:"16px",color:"#3d1500"}}>
        <span>Total</span><span>${(basePrice + total).toFixed(2)}</span>
      </div>
      <p style={{margin:"8px 0 0",fontSize:"10px",color:"#b08050",lineHeight:"1.5"}}>
        Final price confirmed at booking. Payment via Venmo.
      </p>
    </div>
  );
}

// ── GALLERY PAGE ─────────────────────────────────────────────────────────────
const GALLERY_ITEMS = [
  { src: LEI_IMG_1, caption: "Red & Gold Ribbon Lei", tags: ["ribbon","2-color"] },
  { src: LEI_IMG_2, caption: "Money Lei with Beads", tags: ["money","beads","multi-color"] },
  { src: LEI_IMG_3, caption: "GRAD Letter Lei", tags: ["custom text","ribbon","2-color"] },
  { src: LEI_IMG_4, caption: "Full Bow & Ribbon Lei", tags: ["faux leather","multi-color","beads"] },
];

function GalleryPage() {
  const [modal, setModal] = useState(null); // index of open image

  const close = () => setModal(null);

  // Close on escape key
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") close(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  const prev = () => setModal(m => (m - 1 + GALLERY_ITEMS.length) % GALLERY_ITEMS.length);
  const next = () => setModal(m => (m + 1) % GALLERY_ITEMS.length);

  return (
    <div style={{padding:"32px 20px 60px",maxWidth:"860px",margin:"0 auto"}}>
      {/* Header */}
      <div style={{textAlign:"center",marginBottom:"36px"}}>
        <div style={{fontSize:"36px",marginBottom:"8px"}}>📸</div>
        <h2 style={{color:"#5a3000",fontSize:"26px",margin:"0 0 8px",fontFamily:"'Georgia',serif",fontStyle:"italic"}}>Lei Gallery</h2>
        <p style={{color:"#9a7040",fontSize:"14px",fontFamily:"sans-serif",margin:0}}>
          Real examples from our shop — click any photo to zoom in
        </p>
      </div>

      {/* Grid */}
      <div className="gallery-grid" style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(190px,1fr))",gap:"18px"}}>
        {GALLERY_ITEMS.map((item, i) => (
          <div key={i} onClick={() => setModal(i)}
            style={{
              borderRadius:"18px",overflow:"hidden",cursor:"zoom-in",
              boxShadow:"0 4px 20px rgba(0,0,0,0.10)",
              transition:"transform 0.2s, box-shadow 0.2s",
              background:"#f5e8d0",
              position:"relative",
            }}
            onMouseEnter={e => { e.currentTarget.style.transform="scale(1.03)"; e.currentTarget.style.boxShadow="0 10px 36px rgba(0,0,0,0.18)"; }}
            onMouseLeave={e => { e.currentTarget.style.transform="scale(1)"; e.currentTarget.style.boxShadow="0 4px 20px rgba(0,0,0,0.10)"; }}
          >
            <img src={item.src} alt={item.caption}
              style={{width:"100%",aspectRatio:"3/4",objectFit:"cover",display:"block"}}/>
            <div style={{padding:"10px 14px 14px",background:"white"}}>
              <div style={{fontSize:"13px",fontWeight:"700",color:"#3d1500",fontFamily:"sans-serif",marginBottom:"5px"}}>{item.caption}</div>
              <div style={{display:"flex",gap:"5px",flexWrap:"wrap"}}>
                {item.tags.map(t => (
                  <span key={t} style={{background:"#fdf0e0",color:"#c8733a",fontSize:"10px",fontFamily:"sans-serif",padding:"2px 7px",borderRadius:"10px",fontWeight:"600"}}>{t}</span>
                ))}
              </div>
            </div>
            {/* Zoom hint */}
            <div style={{position:"absolute",top:"10px",right:"10px",background:"rgba(0,0,0,0.45)",borderRadius:"20px",padding:"4px 9px",fontSize:"11px",color:"white",fontFamily:"sans-serif",backdropFilter:"blur(4px)"}}>
              🔍 Zoom
            </div>
          </div>
        ))}

        {/* Coming soon placeholder */}
        {[1].map(i => (
          <div key={`ph${i}`} style={{
            borderRadius:"18px",aspectRatio:"3/4",
            background:"linear-gradient(135deg,#fdf0d8,#f5dba0)",
            border:"2px dashed #e5c088",
            display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",
            gap:"10px",color:"#c8933a",fontFamily:"sans-serif",
          }}>
            <span style={{fontSize:"32px"}}>🌺</span>
            <span style={{fontSize:"12px",fontStyle:"italic",color:"#b08050"}}>More coming soon</span>
          </div>
        ))}
      </div>

      <div style={{textAlign:"center",marginTop:"36px",background:"white",borderRadius:"16px",padding:"24px",boxShadow:"0 2px 16px rgba(0,0,0,0.07)"}}>
        <p style={{color:"#7a5520",fontFamily:"sans-serif",fontSize:"14px",lineHeight:"1.7",margin:0}}>
          Every lei is handmade with love — no two are exactly alike! 🌸<br/>
          Ready to order? Head to the <strong>Order</strong> tab above.
        </p>
      </div>

      {/* ── MODAL ── */}
      {modal !== null && (
        <div
          onClick={close}
          style={{
            position:"fixed",inset:0,zIndex:9000,
            background:"rgba(0,0,0,0.88)",
            display:"flex",alignItems:"center",justifyContent:"center",
            padding:"20px",
            backdropFilter:"blur(8px)",
            animation:"modalFadeIn 0.2s ease-out",
          }}>
          <style>{`@keyframes modalFadeIn{from{opacity:0}to{opacity:1}} @keyframes modalImgIn{from{transform:scale(0.92);opacity:0}to{transform:scale(1);opacity:1}}`}</style>

          {/* Close */}
          <button onClick={close} style={{
            position:"absolute",top:"20px",right:"24px",
            background:"rgba(255,255,255,0.12)",border:"none",color:"white",
            width:"44px",height:"44px",borderRadius:"50%",fontSize:"22px",
            cursor:"pointer",zIndex:1,backdropFilter:"blur(4px)",
            display:"flex",alignItems:"center",justifyContent:"center",
          }}>✕</button>

          {/* Prev */}
          {GALLERY_ITEMS.length > 1 && (
            <button onClick={e => { e.stopPropagation(); prev(); }} style={{
              position:"absolute",left:"16px",top:"50%",transform:"translateY(-50%)",
              background:"rgba(255,255,255,0.12)",border:"none",color:"white",
              width:"48px",height:"48px",borderRadius:"50%",fontSize:"24px",
              cursor:"pointer",backdropFilter:"blur(4px)",
            }}>‹</button>
          )}

          {/* Image */}
          <div onClick={e => e.stopPropagation()} style={{
            maxWidth:"min(90vw,560px)",maxHeight:"90vh",
            display:"flex",flexDirection:"column",alignItems:"center",gap:"14px",
            animation:"modalImgIn 0.25s ease-out",
          }}>
            <img src={GALLERY_ITEMS[modal].src} alt={GALLERY_ITEMS[modal].caption}
              style={{
                maxWidth:"100%",maxHeight:"76vh",borderRadius:"16px",
                objectFit:"contain",
                boxShadow:"0 24px 80px rgba(0,0,0,0.6)",
              }}/>
            <div style={{textAlign:"center"}}>
              <div style={{color:"white",fontSize:"16px",fontWeight:"700",fontFamily:"sans-serif",marginBottom:"6px"}}>{GALLERY_ITEMS[modal].caption}</div>
              <div style={{display:"flex",gap:"6px",justifyContent:"center",flexWrap:"wrap"}}>
                {GALLERY_ITEMS[modal].tags.map(t => (
                  <span key={t} style={{background:"rgba(255,210,100,0.2)",color:"#FFD166",fontSize:"11px",fontFamily:"sans-serif",padding:"3px 10px",borderRadius:"12px",fontWeight:"600",border:"1px solid rgba(255,210,100,0.3)"}}>{t}</span>
                ))}
              </div>
              <div style={{color:"rgba(255,255,255,0.4)",fontSize:"12px",fontFamily:"sans-serif",marginTop:"10px"}}>{modal+1} / {GALLERY_ITEMS.length}</div>
            </div>
          </div>

          {/* Next */}
          {GALLERY_ITEMS.length > 1 && (
            <button onClick={e => { e.stopPropagation(); next(); }} style={{
              position:"absolute",right:"16px",top:"50%",transform:"translateY(-50%)",
              background:"rgba(255,255,255,0.12)",border:"none",color:"white",
              width:"48px",height:"48px",borderRadius:"50%",fontSize:"24px",
              cursor:"pointer",backdropFilter:"blur(4px)",
            }}>›</button>
          )}
        </div>
      )}
    </div>
  );
}

// ── COLOR PICKER SECTION ─────────────────────────────────────────────────────
function ColorSection({ selectedColors, setSelectedColors }) {
  const [showMore, setShowMore] = useState(false);
  const [customHex, setCustomHex] = useState("#ff69b4");
  const [customAdded, setCustomAdded] = useState(false);

  const toggleColor = (color) => {
    const isSelected = selectedColors.find(c => c.name === color.name);
    if (isSelected) {
      setSelectedColors(selectedColors.filter(c => c.name !== color.name));
    } else if (selectedColors.length < 3) {
      setSelectedColors([...selectedColors, color]);
    }
  };

  const addCustomColor = () => {
    if (selectedColors.length >= 3) return;
    const custom = { name: "Custom", hex: customHex, dark: false, custom: true };
    const existing = selectedColors.findIndex(c => c.custom);
    if (existing >= 0) {
      const updated = [...selectedColors];
      updated[existing] = custom;
      setSelectedColors(updated);
    } else {
      setSelectedColors([...selectedColors, custom]);
    }
    setCustomAdded(true);
    setTimeout(() => setCustomAdded(false), 1500);
  };

  const colors = showMore ? [...COLOR_WHEEL_12, ...EXTENDED_COLORS] : COLOR_WHEEL_12;

  return (
    <div style={{background:"white",borderRadius:"20px",padding:"26px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"4px"}}>
        <h3 style={{margin:0,color:"#5a3000",fontSize:"17px",fontFamily:"'Georgia',serif"}}>🎨 Colors</h3>
        <span style={{fontFamily:"sans-serif",fontSize:"12px",color:selectedColors.length===3?"#c8400a":"#9a7040",fontWeight:"600"}}>
          {selectedColors.length}/3 selected
        </span>
      </div>
      <p style={{margin:"0 0 14px",fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>
        {showMore ? "All colors shown" : "Showing standard color wheel"} · Choose up to 3
      </p>

      {/* Color wheel label */}
      {!showMore && (
        <p style={{fontSize:"11px",color:"#b08050",margin:"0 0 10px",fontFamily:"sans-serif",letterSpacing:"0.3px"}}>
          PRIMARY · SECONDARY · TERTIARY
        </p>
      )}

      <div style={{display:"flex",flexWrap:"wrap",gap:"9px",marginBottom:"14px"}}>
        {colors.map((color) => {
          const sel = selectedColors.find(c => c.name === color.name);
          const disabled = !sel && selectedColors.length >= 3;
          return (
            <button key={color.name} onClick={() => toggleColor(color)} disabled={disabled} title={color.name}
              style={{
                width:"34px",height:"34px",borderRadius:"50%",background:color.hex,
                border: sel ? "3px solid #c8833a" : "2px solid rgba(0,0,0,0.12)",
                cursor: disabled ? "not-allowed" : "pointer",
                opacity: disabled ? 0.35 : 1,
                transform: sel ? "scale(1.22)" : "scale(1)",
                transition:"all 0.18s",
                boxShadow: sel ? "0 0 0 2px white, 0 0 0 4px #c8833a" : "0 1px 3px rgba(0,0,0,0.15)",
                position:"relative",flexShrink:0,
              }}>
              {sel && <span style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",fontSize:"11px",color:color.dark?"#333":"#fff",fontWeight:"bold"}}>✓</span>}
            </button>
          );
        })}
      </div>

      {/* Toggle more */}
      <button onClick={() => setShowMore(!showMore)}
        style={{background:"none",border:"1px solid #e5c88a",borderRadius:"20px",padding:"5px 14px",
          cursor:"pointer",fontSize:"12px",color:"#c8833a",fontFamily:"sans-serif",fontWeight:"600",marginBottom:"14px"}}>
        {showMore ? "▲ Show standard colors" : "▼ Show more colors"}
      </button>

      {/* Custom color picker — only visible in expanded mode */}
      {showMore && (
      <div style={{background:"#fdf8f0",borderRadius:"12px",padding:"14px",border:"1px solid #edd9a0"}}>
        <p style={{margin:"0 0 8px",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",fontWeight:"600"}}>
          🎨 Custom Color
        </p>
        <div style={{display:"flex",alignItems:"center",gap:"10px",flexWrap:"wrap"}}>
          <input type="color" value={customHex} onChange={e => setCustomHex(e.target.value)}
            style={{width:"42px",height:"36px",border:"none",borderRadius:"8px",cursor:"pointer",background:"none",padding:0}}/>
          <span style={{fontSize:"12px",color:"#9a7040",fontFamily:"monospace"}}>{customHex.toUpperCase()}</span>
          <button onClick={addCustomColor} disabled={selectedColors.length >= 3}
            style={{background: selectedColors.length >= 3 ? "#ddd" : "#c8833a",color:"white",border:"none",
              borderRadius:"8px",padding:"6px 14px",cursor: selectedColors.length >= 3 ? "not-allowed":"pointer",
              fontSize:"12px",fontWeight:"600",fontFamily:"sans-serif",transition:"all 0.2s"}}>
            {customAdded ? "✓ Added!" : "+ Add Custom"}
          </button>
        </div>
        <p style={{margin:"8px 0 0",fontSize:"11px",color:"#b05a20",fontFamily:"sans-serif",lineHeight:"1.4"}}>
          ⚠️ We will do our best to match custom colors — exact shades may vary.
        </p>
      </div>
      )}

      {/* Selected colors chips */}
      {selectedColors.length > 0 && (
        <div style={{marginTop:"14px",display:"flex",gap:"8px",flexWrap:"wrap"}}>
          {selectedColors.map((c, i) => (
            <span key={c.name+i} style={{
              display:"flex",alignItems:"center",gap:"6px",background:"#fdf6ec",
              border:"1px solid #e5c88a",borderRadius:"20px",padding:"4px 10px",
              fontSize:"12px",color:"#7a4010",fontFamily:"sans-serif"
            }}>
              <span style={{width:"10px",height:"10px",borderRadius:"50%",background:c.hex,border:"1px solid rgba(0,0,0,0.2)",display:"inline-block"}}/>
              {i+1}. {c.name}
              <button onClick={() => toggleColor(c)} style={{background:"none",border:"none",cursor:"pointer",color:"#c8833a",padding:0,fontSize:"15px",lineHeight:1}}>×</button>
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

// ── STORAGE HELPERS ──────────────────────────────────────────────────────────
const getStoredOrders = async () => {
  try {
    if (window.storage) {
      const res = await window.storage.get("lei_orders");
      return res ? JSON.parse(res.value) : [];
    }
  } catch {}
  try { return JSON.parse(localStorage.getItem("lei_orders") || "[]"); } catch {}
  return [];
};
const saveStoredOrders = async (orders) => {
  try {
    if (window.storage) { await window.storage.set("lei_orders", JSON.stringify(orders)); return; }
  } catch {}
  try { localStorage.setItem("lei_orders", JSON.stringify(orders)); } catch {}
};

// ── ADMIN PAGE ────────────────────────────────────────────────────────────────
const STATUS_FLOW = [
  { key:"new",              bg:"#fff3cd", color:"#92640a", label:"🆕 New" },
  { key:"emailed",          bg:"#dbeafe", color:"#1e40af", label:"📧 Emailed" },
  { key:"awaiting_payment", bg:"#fde8d8", color:"#9a3412", label:"⏳ Awaiting Payment" },
  { key:"paid",             bg:"#dcfce7", color:"#166534", label:"💰 Paid" },
  { key:"making",           bg:"#ede9fe", color:"#5b21b6", label:"🔨 Making" },
  { key:"date_sent",        bg:"#cffafe", color:"#0e7490", label:"📅 Date Sent" },
  { key:"shipped",          bg:"#d1fae5", color:"#065f46", label:"📦 Shipped / Ready" },
  { key:"delivered",        bg:"#bbf7d0", color:"#14532d", label:"✅ Delivered" },
  { key:"cancelled",        bg:"#fee2e2", color:"#991b1b", label:"❌ Cancelled" },
];
const STATUS_MAP = Object.fromEntries(STATUS_FLOW.map(s => [s.key, s]));

function AdminPage() {
  const [pw, setPw] = useState("");
  const [authed, setAuthed] = useState(false);
  const [error, setError] = useState(false);
  const [orders, setOrders] = useState(null);
  const [expanded, setExpanded] = useState(null);
  const [filter, setFilter] = useState("all");
  const [notesDraft, setNotesDraft] = useState({});

  const reload = async () => {
    try {
      const data = await getStoredOrders();
      setOrders(data);
      const n = {};
      data.forEach(o => { if (o.adminNotes) n[o.id] = o.adminNotes; });
      setNotesDraft(n);
    } catch { setOrders([]); }
  };

  useEffect(() => { if (authed) reload(); }, [authed]);

  const login = () => {
    if (pw === "shelly") { setAuthed(true); setError(false); }
    else { setError(true); }
  };

  const updateStatus = async (id, newStatus) => {
    const data = await getStoredOrders();
    const patched = data.map(o => o.id === id ? { ...o, status: newStatus } : o);
    await saveStoredOrders(patched);
    setOrders(patched);
  };

  const saveNotes = async (id) => {
    const notes = notesDraft[id] || "";
    const data = await getStoredOrders();
    const patched = data.map(o => o.id === id ? { ...o, adminNotes: notes } : o);
    await saveStoredOrders(patched);
    setOrders(patched);
  };

  const deleteOrder = async (id) => {
    const data = await getStoredOrders();
    const patched = data.filter(o => o.id !== id);
    await saveStoredOrders(patched);
    setOrders(patched);
    if (expanded === id) setExpanded(null);
  };

  if (!authed) return (
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#1a0800,#3d1f00)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"sans-serif"}}>
      <div style={{background:"white",borderRadius:"20px",padding:"48px 40px",maxWidth:"360px",width:"90%",textAlign:"center",boxShadow:"0 20px 60px rgba(0,0,0,0.4)"}}>
        <div style={{fontSize:"40px",marginBottom:"12px"}}>🌺</div>
        <h2 style={{margin:"0 0 4px",color:"#3d1500",fontSize:"22px"}}>Admin Access</h2>
        <p style={{margin:"0 0 24px",color:"#9a7040",fontSize:"13px"}}>Fun Leis — Order Dashboard</p>
        <input
          type="password" placeholder="Password" value={pw}
          onChange={e => { setPw(e.target.value); setError(false); }}
          onKeyDown={e => e.key === "Enter" && login()}
          style={{width:"100%",padding:"13px 16px",borderRadius:"10px",border:`2px solid ${error?"#e74c3c":"#e5c88a"}`,
            fontSize:"16px",boxSizing:"border-box",outline:"none",marginBottom:"12px",textAlign:"center",letterSpacing:"4px"}}/>
        {error && <p style={{color:"#e74c3c",fontSize:"12px",margin:"-4px 0 10px"}}>Incorrect password</p>}
        <button onClick={login}
          style={{width:"100%",background:"linear-gradient(135deg,#c8833a,#a85200)",color:"white",border:"none",
            borderRadius:"10px",padding:"13px",fontSize:"15px",fontWeight:"700",cursor:"pointer"}}>
          Enter Dashboard
        </button>
      </div>
    </div>
  );

  const counts = {};
  (orders || []).forEach(o => { const s = o.status || "new"; counts[s] = (counts[s]||0)+1; });
  const filtered = !orders ? [] : filter === "all" ? orders : orders.filter(o => (o.status||"new") === filter);

  return (
    <div style={{minHeight:"100vh",background:"#f5f0e8",fontFamily:"sans-serif"}}>
      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#3d1f00,#7a3d00)",padding:"20px 28px",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:"12px"}}>
        <div>
          <div style={{color:"#FFD166",fontSize:"18px",fontWeight:"800",letterSpacing:"2px"}}>🌺 FUN LEIS</div>
          <div style={{color:"rgba(255,220,150,0.7)",fontSize:"12px",marginTop:"2px"}}>Admin Dashboard</div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:"12px"}}>
          {orders && <span style={{color:"rgba(255,220,150,0.8)",fontSize:"13px"}}>{orders.length} order{orders.length!==1?"s":""} total</span>}
          <button onClick={reload} style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.2)",color:"white",borderRadius:"8px",padding:"6px 14px",cursor:"pointer",fontSize:"12px"}}>↺ Refresh</button>
          <button onClick={() => window.location.hash=""} style={{background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.2)",color:"white",borderRadius:"8px",padding:"6px 14px",cursor:"pointer",fontSize:"12px"}}>← Back to Site</button>
        </div>
      </div>

      {/* Status filter tabs */}
      <div style={{background:"white",borderBottom:"1px solid #e8d8b8",overflowX:"auto"}}>
        <div style={{display:"flex",gap:"0",maxWidth:"900px",margin:"0 auto",padding:"0 20px"}}>
          {[{key:"all",label:"All",bg:"#f5f0e8",color:"#5a3000"},...STATUS_FLOW].map(s => {
            const isActive = filter === s.key;
            const cnt = s.key === "all" ? (orders||[]).length : (counts[s.key]||0);
            return (
              <button key={s.key} onClick={() => setFilter(s.key)}
                style={{padding:"12px 14px",border:"none",borderBottom:isActive?"3px solid #c8833a":"3px solid transparent",
                  background:"transparent",cursor:"pointer",whiteSpace:"nowrap",
                  fontSize:"12px",fontWeight:isActive?"700":"500",
                  color:isActive?"#c8833a":"#9a7040",transition:"all 0.15s",flexShrink:0}}>
                {s.label} {cnt > 0 && <span style={{background:isActive?"#c8833a":s.bg||"#eee",color:isActive?"white":s.color||"#666",borderRadius:"10px",padding:"1px 6px",fontSize:"10px",marginLeft:"4px"}}>{cnt}</span>}
              </button>
            );
          })}
        </div>
      </div>

      <div style={{maxWidth:"900px",margin:"0 auto",padding:"24px 20px"}}>
        {orders === null && (
          <div style={{textAlign:"center",padding:"60px",color:"#9a7040",fontSize:"15px"}}>Loading orders…</div>
        )}
        {orders !== null && filtered.length === 0 && (
          <div style={{textAlign:"center",padding:"60px",background:"white",borderRadius:"16px",boxShadow:"0 2px 12px rgba(0,0,0,0.06)"}}>
            <div style={{fontSize:"48px",marginBottom:"12px"}}>{orders.length === 0 ? "📭" : "🔍"}</div>
            <p style={{color:"#9a7040",fontSize:"15px",margin:0}}>{orders.length === 0 ? "No orders yet — they'll appear here when customers submit." : "No orders with this status."}</p>
          </div>
        )}
        {filtered.map(order => {
          const st = order.status || "new";
          const sc = STATUS_MAP[st] || STATUS_MAP["new"];
          const isOpen = expanded === order.id;
          const d = order.design || {};
          const c = order.contact || {};
          const date = new Date(order.submittedAt);
          const dateStr = date.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"});
          const timeStr = date.toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"});
          const themeStr = (d.themes||[]).map(v=>{const t=THEME_OPTIONS.find(o=>o.value===v);return t?`${t.emoji} ${t.label}`:"";}).join(", ");

          return (
            <div key={order.id} style={{background:"white",borderRadius:"16px",marginBottom:"14px",boxShadow:"0 2px 12px rgba(0,0,0,0.06)",overflow:"hidden",border:`2px solid ${isOpen?"#c8833a":"transparent"}`,transition:"border-color 0.2s"}}>
              {/* Row header */}
              <div onClick={() => setExpanded(isOpen ? null : order.id)}
                className="admin-row" style={{display:"grid",gridTemplateColumns:"1fr auto auto auto",gap:"16px",alignItems:"center",padding:"16px 20px",cursor:"pointer"}}>
                <div>
                  <div style={{fontWeight:"700",fontSize:"15px",color:"#3d1500"}}>{c.recipientName || "—"} <span style={{fontWeight:"400",color:"#9a7040",fontSize:"13px"}}>for {c.parentName || "—"}</span></div>
                  <div style={{fontSize:"12px",color:"#9a7040",marginTop:"3px"}}>
                    {dateStr} {timeStr} · <a href={`mailto:${c.email}`} onClick={e=>e.stopPropagation()} style={{color:"#c8833a"}}>{c.email}</a> · <a href={`tel:${c.phone}`} onClick={e=>e.stopPropagation()} style={{color:"#c8833a"}}>{c.phone}</a>
                  </div>
                  <div style={{fontSize:"12px",color:"#b08050",marginTop:"3px"}}>
                    {(d.colors||[]).join(", ")||"—"}
                    {d.hasMoney?` · 💵 ${d.billCount}x$${d.billDenom}`:""}
                    {d.hasBeads?` · ✨ Beads`:""}
                    {d.hasFauxLeather?` · 🍂 Leather`:""}
                    {themeStr?` · ${themeStr}`:""}
                    {d.customText?` · "${d.customText}"`:""}
                  </div>
                </div>
                <div style={{fontWeight:"800",fontSize:"16px",color:"#3d1500",whiteSpace:"nowrap"}}>${(order.total||0).toFixed(2)}</div>
                <span style={{background:sc.bg,color:sc.color,padding:"4px 10px",borderRadius:"20px",fontSize:"12px",fontWeight:"600",whiteSpace:"nowrap"}}>{sc.label}</span>
                <span style={{color:"#c8833a",fontSize:"18px",transform:isOpen?"rotate(90deg)":"",transition:"transform 0.2s",display:"inline-block"}}>›</span>
              </div>

              {/* Expanded detail */}
              {isOpen && (
                <div style={{borderTop:"1px solid #f0e8d8",background:"#fffdf8"}}>
                  {/* Contact + Design */}
                  <div className="admin-detail" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0",borderBottom:"1px solid #f0e8d8"}}>
                    <div style={{padding:"20px",borderRight:"1px solid #f0e8d8"}}>
                      <h4 style={{margin:"0 0 12px",color:"#5a3000",fontSize:"12px",textTransform:"uppercase",letterSpacing:"1px"}}>📋 Contact</h4>
                      <div style={{fontSize:"13px",color:"#5a4020",lineHeight:"2"}}>
                        <div><strong>Ordered by:</strong> {c.parentName}</div>
                        <div><strong>Recipient:</strong> {c.recipientName}</div>
                        <div><strong>Email:</strong> <a href={`mailto:${c.email}`} style={{color:"#c8833a",fontWeight:"600"}}>{c.email}</a></div>
                        <div><strong>Phone:</strong> <a href={`tel:${c.phone}`} style={{color:"#c8833a",fontWeight:"600"}}>{c.phone}</a></div>
                        {c.notes && <div style={{marginTop:"6px",background:"#fef9ec",borderRadius:"8px",padding:"8px 10px",border:"1px solid #f0d88a"}}><strong>Customer notes:</strong><br/>{c.notes}</div>}
                      </div>
                    </div>
                    <div style={{padding:"20px"}}>
                      <h4 style={{margin:"0 0 12px",color:"#5a3000",fontSize:"12px",textTransform:"uppercase",letterSpacing:"1px"}}>🎨 Design</h4>
                      <div style={{fontSize:"13px",color:"#5a4020",lineHeight:"2"}}>
                        <div><strong>Colors:</strong> {(d.colors||[]).join(", ")||"—"}</div>
                        <div><strong>Money:</strong> {d.hasMoney ? `${d.billCount}x $${d.billDenom} bills` : "No"}</div>
                        <div><strong>Beads:</strong> {d.hasBeads ? `Yes (${d.beadAmount})` : "No"}</div>
                        <div><strong>Faux Leather:</strong> {d.hasFauxLeather ? `${d.leatherAmount}, ${d.leatherColor}` : "No"}</div>
                        <div><strong>Themes:</strong> {themeStr||"None"}{(d.themes||[]).includes("other")&&d.otherCelebrationDesc?` — ${d.otherCelebrationDesc}`:""}</div>
                        {d.customText && <div><strong>Custom Text:</strong> "{d.customText}"</div>}
                        <div style={{marginTop:"6px",fontWeight:"700",fontSize:"14px",color:"#3d1500"}}>Total: ${(order.total||0).toFixed(2)}</div>
                      </div>
                    </div>
                  </div>

                  {/* Status pipeline */}
                  <div style={{padding:"16px 20px",borderBottom:"1px solid #f0e8d8"}}>
                    <div style={{fontSize:"12px",color:"#9a7040",fontWeight:"600",marginBottom:"10px"}}>SET STATUS</div>
                    <div className="admin-status-row" style={{display:"flex",gap:"7px",flexWrap:"wrap"}}>
                      {STATUS_FLOW.map(s => (
                        <button key={s.key} onClick={() => updateStatus(order.id, s.key)}
                          style={{padding:"6px 13px",borderRadius:"20px",border:`2px solid ${st===s.key?s.color:"#e0c89a"}`,
                            background:st===s.key?s.bg:"white",color:st===s.key?s.color:"#9a7040",
                            cursor:"pointer",fontSize:"12px",fontWeight:st===s.key?"700":"500",transition:"all 0.15s",
                            boxShadow:st===s.key?"0 2px 8px rgba(0,0,0,0.10)":"none"}}>
                          {s.label}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Admin notes */}
                  <div style={{padding:"16px 20px",borderBottom:"1px solid #f0e8d8"}}>
                    <div style={{fontSize:"12px",color:"#9a7040",fontWeight:"600",marginBottom:"8px"}}>ADMIN NOTES</div>
                    <div style={{display:"flex",gap:"10px",alignItems:"flex-start"}}>
                      <textarea
                        value={notesDraft[order.id]||""}
                        onChange={e => setNotesDraft(prev=>({...prev,[order.id]:e.target.value}))}
                        placeholder="Venmo handle, pickup date, special instructions…"
                        rows={2}
                        style={{flex:1,padding:"9px 12px",borderRadius:"8px",border:"1.5px solid #e0c89a",fontSize:"13px",fontFamily:"sans-serif",resize:"vertical",outline:"none",background:"#fffdf8"}}
                      />
                      <button onClick={() => saveNotes(order.id)}
                        style={{padding:"9px 16px",borderRadius:"8px",background:"#c8833a",color:"white",border:"none",cursor:"pointer",fontSize:"12px",fontWeight:"600",whiteSpace:"nowrap"}}>
                        Save
                      </button>
                    </div>
                  </div>

                  {/* Delete */}
                  <div style={{padding:"12px 20px",display:"flex",justifyContent:"flex-end"}}>
                    <button onClick={() => { if(window.confirm("Delete this order? This cannot be undone.")) deleteOrder(order.id); }}
                      style={{padding:"6px 16px",borderRadius:"20px",border:"2px solid #fca5a5",
                        background:"white",color:"#dc2626",cursor:"pointer",fontSize:"12px",fontWeight:"600"}}>
                      🗑 Delete Order
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── ROUTER ────────────────────────────────────────────────────────────────────
function App() {
  const [page, setPage] = useState(window.location.hash === "#admin" ? "admin" : "main");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (window.location.hash !== "#admin") setLoading(true);
  }, []);

  useEffect(() => {
    const handler = () => setPage(window.location.hash === "#admin" ? "admin" : "main");
    window.addEventListener("hashchange", handler);
    return () => window.removeEventListener("hashchange", handler);
  }, []);

  return (
    <>
      {loading && <LoadingScreen onDone={() => setLoading(false)} />}
      {page === "admin" ? <AdminPage /> : <LeiOrderForm />}
    </>
  );
}

// ── MAIN COMPONENT ────────────────────────────────────────────────────────────
export default App;

function LeiOrderForm() {
  const [activeTab, setActiveTab] = useState("order");
  const [step, setStep] = useState(1);

  // Design selections
  const [selectedColors, setSelectedColors] = useState([]);
  const [hasMoney, setHasMoney] = useState(null);
  const [billDenom, setBillDenom] = useState(1);
  const [billCount, setBillCount] = useState(1);
  const [hasBeads, setHasBeads] = useState(null);
  const [beadAmount, setBeadAmount] = useState(null);
  const [hasFauxLeather, setHasFauxLeather] = useState(null);
  const [leatherAmount, setLeatherAmount] = useState(null);
  const [leatherColor, setLeatherColor] = useState("brown");
  const [themes, setThemes] = useState([]);
  const [otherCelebrationDesc, setOtherCelebrationDesc] = useState("");
  const [customWords, setCustomWords] = useState([""]);

  // Contact info
  const [form, setForm] = useState({ parentName:"", email:"", phone:"", recipientName:"", notes:"" });
  const [submitted, setSubmitted] = useState(false);

  // ── CUSTOM TEXT LOGIC ──
  const combinedText = customWords.filter(w => w.trim()).join(" ");
  const totalChars = combinedText.length;
  const MAX_CHARS = 15;
  const canAddWord = customWords.length < 3 && totalChars < MAX_CHARS - 1;

  const addWord = () => { if (canAddWord) setCustomWords([...customWords, ""]); };
  const updateWord = (i, val) => {
    const newWords = [...customWords];
    newWords[i] = val;
    const combined = newWords.filter(w => w.trim()).join(" ");
    if (combined.length <= MAX_CHARS) setCustomWords(newWords);
  };
  const removeWord = (i) => setCustomWords(customWords.filter((_,idx) => idx !== i));

  const textCost = totalChars === 0 ? 0 : totalChars <= 8 ? 10 : 10 + (totalChars - 8);

  // ── PRICING ──
  const pricing = useMemo(() => {
    const items = [];
    let total = 0;

    if (hasMoney === true && billCount > 0) {
      const cost = billCount * (billDenom + 1);
      items.push({ label: `${billCount}x $${billDenom} bills (face + $1/bill labor)`, cost });
      total += cost;
    }
    if (hasBeads === true && beadAmount) {
      const beadCosts = { small: 5, medium: 10, large: 20 };
      const cost = beadCosts[beadAmount];
      items.push({ label: `Beads — ${beadAmount} amount`, cost });
      total += cost;
    }
    if (hasFauxLeather === true && leatherAmount) {
      const leatherCosts = { small: 5, large: 20 };
      const cost = leatherCosts[leatherAmount];
      items.push({ label: `Faux Leather — ${leatherAmount} amount`, cost });
      total += cost;
    }
    if (themes.length > 0) {
      const themeLabels = themes.map(v => { const t = THEME_OPTIONS.find(o=>o.value===v); return `${t.emoji} ${t.label}`; }).join(", ");
      items.push({ label: `Theme: ${themeLabels}`, cost: 0 });
    }
    if (textCost > 0) {
      items.push({ label: `Custom text "${combinedText}" (${totalChars} chars)`, cost: textCost });
      total += textCost;
    }

    return { items, total };
  }, [hasMoney, billDenom, billCount, hasBeads, beadAmount, hasFauxLeather, leatherAmount, themes, textCost, combinedText, totalChars]);

  // ── VALIDATION ──
  const step1Valid = selectedColors.length >= 1
    && hasMoney !== null
    && (hasMoney === false || (billCount > 0))
    && hasBeads !== null
    && (hasBeads === false || beadAmount !== null)
    && hasFauxLeather !== null
    && (hasFauxLeather === false || leatherAmount !== null);

  const step2Valid = form.parentName && form.email && form.phone && form.recipientName;

  // ── SUBMIT ──
  const handleSubmit = async () => {
    const order = {
      id: Date.now(),
      submittedAt: new Date().toISOString(),
      status: "new",
      contact: { ...form },
      design: {
        colors: selectedColors.map(c => c.name),
        hasMoney, billDenom, billCount,
        hasBeads, beadAmount,
        hasFauxLeather, leatherAmount, leatherColor,
        themes,
        otherCelebrationDesc: themes.includes("other") ? otherCelebrationDesc : "",
        customText: combinedText,
      },
      total: BASE_LEI_PRICE + pricing.total,
    };
    try {
      const existing = await getStoredOrders();
      existing.unshift(order);
      await saveStoredOrders(existing);
    } catch (e) {}
    setSubmitted(true);
  };

  // ── SUCCESS STATE ──
  if (submitted) {
    return (
      <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#fdf6ec,#fce4b8)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Georgia',serif",padding:"24px"}}>
        <div style={{background:"white",borderRadius:"24px",padding:"48px 36px",textAlign:"center",maxWidth:"460px",width:"100%",boxShadow:"0 20px 60px rgba(0,0,0,0.1)"}}>
          <div style={{fontSize:"56px",marginBottom:"12px"}}>🌺</div>
          <h2 style={{fontSize:"26px",color:"#5a3e1b",marginBottom:"8px",fontStyle:"italic"}}>Order Received!</h2>
          <p style={{color:"#8a6a40",lineHeight:"1.7",marginBottom:"20px",fontFamily:"sans-serif",fontSize:"14px"}}>
            Thank you, <strong>{form.parentName}</strong>! We're so excited to make a custom lei for <strong>{form.recipientName}</strong>. 🌸<br/><br/>
            We will reach out to <strong>{form.email}</strong> to confirm your order details and send payment instructions via <strong>Venmo</strong>. Each lei is made by hand, just for you!
          </p>
          <div style={{background:"#fdf6ec",borderRadius:"12px",padding:"16px",textAlign:"left",fontSize:"13px",color:"#6a4e2a",fontFamily:"sans-serif",lineHeight:"1.8",marginBottom:"20px"}}>
            <div><strong>Colors:</strong> {selectedColors.map(c=>c.name).join(", ") || "—"}</div>
            <div><strong>Theme:</strong> {themes.length > 0 ? themes.map(v => { const t=THEME_OPTIONS.find(o=>o.value===v); return `${t.emoji} ${t.label}`; }).join(", ") : "None"}{themes.includes("other") && otherCelebrationDesc ? ` — ${otherCelebrationDesc}` : ""}</div>
            <div><strong>Money Lei:</strong> {hasMoney ? `Yes — ${billCount}x $${billDenom}` : "No"}</div>
            <div><strong>Beads:</strong> {hasBeads ? `Yes (${beadAmount})` : "No"}</div>
            <div><strong>Faux Leather:</strong> {hasFauxLeather ? `Yes — ${leatherAmount}, ${leatherColor}` : "No"}</div>
            {combinedText && <div><strong>Custom Text:</strong> {combinedText}</div>}
            <div style={{borderTop:"1px dashed #ddd",marginTop:"8px",paddingTop:"8px",fontWeight:"700",fontSize:"14px"}}>
              Estimated Total: ${(BASE_LEI_PRICE + pricing.total).toFixed(2)}
            </div>
          </div>
          <button onClick={() => { setSubmitted(false); setStep(1); setSelectedColors([]); setHasMoney(null); setBillDenom(1); setBillCount(1); setHasBeads(null); setBeadAmount(null); setHasFauxLeather(null); setLeatherAmount(null); setLeatherColor("brown"); setThemes([]); setOtherCelebrationDesc(""); setCustomWords([""]); setForm({parentName:"",email:"",phone:"",recipientName:"",notes:""}); }}
            style={{background:"linear-gradient(135deg,#c8833a,#a85200)",color:"white",border:"none",borderRadius:"12px",padding:"12px 28px",cursor:"pointer",fontSize:"14px",fontWeight:"600",fontFamily:"sans-serif"}}>
            Place Another Order
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#fdf6ec 0%,#fce8c0 55%,#fad9a0 100%)",fontFamily:"'Georgia','Times New Roman',serif"}}>
      {/* Header */}
      <div className="site-header" style={{background:"linear-gradient(135deg,#3d1f00,#7a3d00,#a85200)",padding:"36px 24px 28px",textAlign:"center",position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",top:0,left:0,right:0,bottom:0,opacity:0.05,backgroundImage:"repeating-linear-gradient(45deg,#fff 0,#fff 1px,transparent 0,transparent 50%)",backgroundSize:"12px 12px"}}/>
        <div style={{position:"relative"}}>
          <div style={{fontSize:"36px",marginBottom:"6px"}}>🌺 🎊 🌺</div>
          <h1 style={{color:"#FFD166",fontSize:"clamp(22px,5vw,36px)",margin:"0 0 5px",letterSpacing:"4px",textTransform:"uppercase",textShadow:"0 2px 8px rgba(0,0,0,0.3)"}}>
            Fun Leis
          </h1>
          <p style={{color:"rgba(255,220,150,0.85)",margin:0,fontSize:"14px",letterSpacing:"1px",fontStyle:"italic"}}>
            Handmade with love · Custom orders
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div className="tab-bar" style={{display:"flex",borderBottom:"2px solid #e8c880",background:"rgba(255,248,230,0.9)",position:"sticky",top:0,zIndex:10}}>
        {[{id:"order",label:"🌺 Place Order"},{id:"gallery",label:"📸 Gallery"}].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)}
            style={{
              flex:1,padding:"14px",border:"none",background:"none",cursor:"pointer",
              fontSize:"14px",fontWeight:"700",fontFamily:"sans-serif",letterSpacing:"0.5px",
              color: activeTab===tab.id ? "#a85200" : "#9a7040",
              borderBottom: activeTab===tab.id ? "3px solid #c8833a" : "3px solid transparent",
              marginBottom:"-2px",transition:"all 0.2s"
            }}>
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === "gallery" && <GalleryPage />}

      {activeTab === "order" && (
        <div style={{maxWidth:"960px",margin:"0 auto",padding:"28px 18px 60px"}}>
          {/* Step indicators */}
          <div className="step-ind" style={{display:"flex",justifyContent:"center",alignItems:"center",gap:"8px",marginBottom:"30px"}}>
            {[{n:1,label:"Design Your Lei"},{n:2,label:"Your Info"}].map((s,i,arr) => (
              <div key={s.n} style={{display:"flex",alignItems:"center",gap:"8px"}}>
                <div style={{
                  width:"32px",height:"32px",borderRadius:"50%",
                  background: step>s.n ? "#4caf50" : step===s.n ? "#c8833a" : "#d9c4a0",
                  color:"white",display:"flex",alignItems:"center",justifyContent:"center",
                  fontSize:step>s.n?"16px":"14px",fontWeight:"bold",fontFamily:"sans-serif",transition:"all 0.3s"
                }}>{step>s.n?"✓":s.n}</div>
                <span style={{fontSize:"13px",color:step>=s.n?"#7a3d00":"#b0926a",fontFamily:"sans-serif",fontWeight:step===s.n?"700":"400"}}>{s.label}</span>
                {i < arr.length-1 && <span style={{color:"#d0a860",fontSize:"18px",margin:"0 4px"}}>›</span>}
              </div>
            ))}
          </div>

          {/* ── STEP 1 ── */}
          {step === 1 && (
            <div style={{display:"grid",gridTemplateColumns:"1fr 340px",gap:"24px",alignItems:"start"}} className="order-grid">
              {/* LEFT COLUMN */}
              <div style={{display:"flex",flexDirection:"column",gap:"20px"}}>

                <ColorSection selectedColors={selectedColors} setSelectedColors={setSelectedColors} />

                {/* MONEY */}
                <div style={{background:"white",borderRadius:"20px",padding:"24px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                  <h3 style={{margin:"0 0 4px",color:"#5a3000",fontSize:"17px"}}>💵 Include Money?</h3>
                  <p style={{margin:"0 0 14px",fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>Bills folded and woven into the lei</p>
                  <div style={{display:"flex",gap:"10px",marginBottom:"14px"}}>
                    {["Yes","No"].map(opt => (
                      <button key={opt} onClick={() => setHasMoney(opt==="Yes")}
                        style={{flex:1,padding:"12px",borderRadius:"12px",border:"2px solid",
                          borderColor: hasMoney===(opt==="Yes") ? "#c8833a":"#e0c89a",
                          background: hasMoney===(opt==="Yes") ? "#fdf0e0":"white",
                          color: hasMoney===(opt==="Yes") ? "#7a3a00":"#9a7040",
                          cursor:"pointer",fontSize:"14px",fontWeight:"600",fontFamily:"sans-serif",transition:"all 0.2s"}}>
                        {opt==="Yes"?"✅ Yes":"❌ No"}
                      </button>
                    ))}
                  </div>
                  {hasMoney === true && (
                    <div style={{background:"#fdf8f0",borderRadius:"12px",padding:"14px",border:"1px solid #edd9a0"}}>
                      <p style={{margin:"0 0 10px",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",fontWeight:"600"}}>Denomination</p>
                      <div className="denom-row" style={{display:"flex",gap:"8px",marginBottom:"14px",flexWrap:"wrap"}}>
                        {[1,5,10,20].map(d => (
                          <button key={d} onClick={() => setBillDenom(d)}
                            style={{padding:"8px 16px",borderRadius:"10px",border:"2px solid",
                              borderColor: billDenom===d ? "#5a8c30":"#e0c89a",
                              background: billDenom===d ? "#e8f5d8":"white",
                              color: billDenom===d ? "#2d5010":"#7a5520",
                              cursor:"pointer",fontSize:"14px",fontWeight:"700",fontFamily:"sans-serif"}}>
                            ${d}
                          </button>
                        ))}
                      </div>
                      <p style={{margin:"0 0 8px",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",fontWeight:"600"}}>Number of Bills</p>
                      <div style={{display:"flex",alignItems:"center",gap:"12px"}}>
                        <button onClick={() => setBillCount(Math.max(1,billCount-1))}
                          style={{width:"34px",height:"34px",borderRadius:"50%",border:"2px solid #e0c89a",background:"white",cursor:"pointer",fontSize:"18px",color:"#c8833a",fontWeight:"bold",lineHeight:1}}>−</button>
                        <span style={{fontSize:"22px",fontWeight:"700",color:"#3d1500",fontFamily:"sans-serif",minWidth:"32px",textAlign:"center"}}>{billCount}</span>
                        <button onClick={() => setBillCount(Math.min(30, billCount+1))}
                          style={{width:"34px",height:"34px",borderRadius:"50%",border:"2px solid #e0c89a",background:"white",cursor:"pointer",fontSize:"18px",color:"#c8833a",fontWeight:"bold",lineHeight:1}}>+</button>
                        <span style={{fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>
                          = ${billCount*(billDenom+1)} ({billCount} × ${billDenom} + $1/bill labor)
                        </span>
                      </div>
                    </div>
                  )}
                </div>

                {/* BEADS */}
                <div style={{background:"white",borderRadius:"20px",padding:"24px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"4px"}}>
                    <h3 style={{margin:0,color:"#5a3000",fontSize:"17px"}}>✨ Add Beads?</h3>
                    <span style={{background:"#e8f0ff",color:"#3a4a8c",fontSize:"11px",padding:"3px 10px",borderRadius:"20px",fontFamily:"sans-serif",fontWeight:"600"}}>+ Extra Cost</span>
                  </div>
                  <p style={{margin:"0 0 14px",fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>Decorative beads interwoven throughout</p>
                  <div style={{display:"flex",gap:"10px",marginBottom:"14px"}}>
                    {["Yes","No"].map(opt => (
                      <button key={opt} onClick={() => setHasBeads(opt==="Yes")}
                        style={{flex:1,padding:"12px",borderRadius:"12px",border:"2px solid",
                          borderColor: hasBeads===(opt==="Yes") ? "#5c6bbf":"#e0c89a",
                          background: hasBeads===(opt==="Yes") ? "#eef0ff":"white",
                          color: hasBeads===(opt==="Yes") ? "#3a4a9c":"#9a7040",
                          cursor:"pointer",fontSize:"14px",fontWeight:"600",fontFamily:"sans-serif",transition:"all 0.2s"}}>
                        {opt==="Yes"?"✅ Yes":"❌ No"}
                      </button>
                    ))}
                  </div>
                  {hasBeads === true && (
                    <div style={{display:"flex",gap:"10px",flexWrap:"wrap"}}>
                      {[{v:"small",label:"Small",price:5,desc:"A few accents"},{v:"medium",label:"Medium",price:10,desc:"Moderate coverage"},{v:"large",label:"Large",price:20,desc:"Fully beaded"}].map(opt => (
                        <button key={opt.v} onClick={() => setBeadAmount(opt.v)}
                          style={{flex:1,minWidth:"90px",padding:"12px 8px",borderRadius:"12px",border:"2px solid",textAlign:"center",
                            borderColor: beadAmount===opt.v ? "#5c6bbf":"#e0c89a",
                            background: beadAmount===opt.v ? "#eef0ff":"white",
                            cursor:"pointer",fontFamily:"sans-serif"}}>
                          <div style={{fontWeight:"700",fontSize:"14px",color: beadAmount===opt.v ? "#3a4a9c":"#5a4020"}}>{opt.label}</div>
                          <div style={{fontSize:"11px",color:"#9a7040",marginTop:"2px"}}>{opt.desc}</div>
                          <div style={{fontSize:"13px",fontWeight:"700",color:"#3a4a9c",marginTop:"4px"}}>${opt.price}</div>
                        </button>
                      ))}
                    </div>
                  )}
                </div>

                {/* FAUX LEATHER */}
                <div style={{background:"white",borderRadius:"20px",padding:"24px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"4px"}}>
                    <h3 style={{margin:0,color:"#5a3000",fontSize:"17px"}}>🍂 Faux Leather?</h3>
                    <span style={{background:"#f5e8d8",color:"#7a4015",fontSize:"11px",padding:"3px 10px",borderRadius:"20px",fontFamily:"sans-serif",fontWeight:"600"}}>+ Extra Cost</span>
                  </div>
                  <p style={{margin:"0 0 14px",fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>Premium faux leather accent pieces</p>
                  <div style={{display:"flex",gap:"10px",marginBottom:"14px"}}>
                    {["Yes","No"].map(opt => (
                      <button key={opt} onClick={() => setHasFauxLeather(opt==="Yes")}
                        style={{flex:1,padding:"12px",borderRadius:"12px",border:"2px solid",
                          borderColor: hasFauxLeather===(opt==="Yes") ? "#a0622a":"#e0c89a",
                          background: hasFauxLeather===(opt==="Yes") ? "#fdf0e8":"white",
                          color: hasFauxLeather===(opt==="Yes") ? "#7a3a10":"#9a7040",
                          cursor:"pointer",fontSize:"14px",fontWeight:"600",fontFamily:"sans-serif",transition:"all 0.2s"}}>
                        {opt==="Yes"?"✅ Yes":"❌ No"}
                      </button>
                    ))}
                  </div>
                  {hasFauxLeather === true && (
                    <div style={{display:"flex",flexDirection:"column",gap:"10px"}}>
                      <div style={{display:"flex",gap:"10px"}}>
                        {[{v:"small",label:"Small",price:5,desc:"Subtle accents"},{v:"large",label:"Large",price:20,desc:"Bold statement"}].map(opt => (
                          <button key={opt.v} onClick={() => setLeatherAmount(opt.v)}
                            style={{flex:1,padding:"12px 8px",borderRadius:"12px",border:"2px solid",textAlign:"center",
                              borderColor: leatherAmount===opt.v ? "#a0622a":"#e0c89a",
                              background: leatherAmount===opt.v ? "#fdf0e8":"white",
                              cursor:"pointer",fontFamily:"sans-serif"}}>
                            <div style={{fontWeight:"700",fontSize:"14px",color: leatherAmount===opt.v ? "#7a3a10":"#5a4020"}}>{opt.label}</div>
                            <div style={{fontSize:"11px",color:"#9a7040",marginTop:"2px"}}>{opt.desc}</div>
                            <div style={{fontSize:"13px",fontWeight:"700",color:"#a0622a",marginTop:"4px"}}>${opt.price}</div>
                          </button>
                        ))}
                      </div>
                      <div style={{marginTop:"4px"}}>
                        <p style={{margin:"0 0 8px",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",fontWeight:"600"}}>Leather Color</p>
                        <div style={{display:"flex",gap:"10px"}}>
                          {[{v:"brown",label:"Brown",swatch:"#7B3F10"},{v:"black",label:"Black",swatch:"#1a1a1a"}].map(opt => (
                            <button key={opt.v} onClick={() => setLeatherColor(opt.v)}
                              style={{flex:1,display:"flex",alignItems:"center",gap:"10px",padding:"10px 14px",
                                borderRadius:"12px",border:"2px solid",
                                borderColor: leatherColor===opt.v ? "#a0622a":"#e0c89a",
                                background: leatherColor===opt.v ? "#fdf0e8":"white",
                                cursor:"pointer",fontFamily:"sans-serif",transition:"all 0.2s"}}>
                              <span style={{width:"22px",height:"22px",borderRadius:"50%",background:opt.swatch,border:"2px solid rgba(255,255,255,0.5)",boxShadow:"0 1px 4px rgba(0,0,0,0.3)",flexShrink:0}}/>
                              <span style={{fontWeight:"700",fontSize:"14px",color: leatherColor===opt.v ? "#7a3a10":"#5a4020"}}>{opt.label}</span>
                              {leatherColor===opt.v && <span style={{marginLeft:"auto",color:"#c8833a",fontSize:"14px"}}>✓</span>}
                            </button>
                          ))}
                        </div>
                      </div>
                    </div>
                  )}
                </div>

                {/* THEME */}
                <div style={{background:"white",borderRadius:"20px",padding:"24px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"4px"}}>
                    <h3 style={{margin:0,color:"#5a3000",fontSize:"17px"}}>🎊 Occasion / Theme</h3>
                    <span style={{fontFamily:"sans-serif",fontSize:"12px",color:themes.length===3?"#c8400a":"#9a7040",fontWeight:"600"}}>{themes.length}/3 selected</span>
                  </div>
                  <p style={{margin:"0 0 14px",fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>
                    Optional · Up to 3 themes — we'll incorporate them into your lei design. ✨
                  </p>
                  <div style={{display:"flex",flexWrap:"wrap",gap:"8px"}}>
                    {THEME_OPTIONS.map(opt => {
                      const sel = themes.includes(opt.value);
                      const disabled = !sel && themes.length >= 3;
                      return (
                        <button key={opt.value}
                          onClick={() => {
                            if (sel) setThemes(themes.filter(v => v !== opt.value));
                            else if (!disabled) setThemes([...themes, opt.value]);
                          }}
                          disabled={disabled}
                          style={{padding:"8px 14px",borderRadius:"20px",border:"2px solid",
                            borderColor: sel ? "#c8833a":"#e0c89a",
                            background: sel ? "#fdf0e0":"white",
                            color: sel ? "#7a3a00": disabled ? "#ccc" : "#7a5520",
                            cursor: disabled ? "not-allowed":"pointer",
                            fontSize:"13px",fontWeight: sel ? "700":"500",
                            fontFamily:"sans-serif",transition:"all 0.15s",
                            opacity: disabled ? 0.5 : 1}}>
                          {opt.emoji} {opt.label}
                        </button>
                      );
                    })}
                  </div>
                  {themes.includes("other") && (
                    <div style={{marginTop:"12px"}}>
                      <label style={{display:"block",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",fontWeight:"600",marginBottom:"6px"}}>
                        🎉 Describe your celebration
                      </label>
                      <input
                        type="text"
                        placeholder="e.g. Quinceañera, Retirement, Bar Mitzvah…"
                        value={otherCelebrationDesc}
                        onChange={e => setOtherCelebrationDesc(e.target.value)}
                        style={{width:"100%",boxSizing:"border-box",padding:"10px 14px",borderRadius:"10px",border:"1.5px solid #e0c89a",fontSize:"13px",fontFamily:"sans-serif",color:"#3d1500",background:"#fffdf8",outline:"none"}}
                      />
                    </div>
                  )}
                  {themes.length > 0 && (
                    <p style={{margin:"12px 0 0",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",background:"#fdf8f0",padding:"10px 14px",borderRadius:"10px",border:"1px solid #edd9a0"}}>
                      🌸 We'll incorporate <strong>{themes.map(v => { const t=THEME_OPTIONS.find(o=>o.value===v); return `${t.emoji} ${t.label}`; }).join(", ")}</strong> elements into your lei design!
                    </p>
                  )}
                </div>

                {/* CUSTOM TEXT */}
                <div style={{background:"white",borderRadius:"20px",padding:"24px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"4px"}}>
                    <h3 style={{margin:0,color:"#5a3000",fontSize:"17px"}}>✍️ Custom Text</h3>
                    <span style={{background:"#f0f8e8",color:"#3a7020",fontSize:"11px",padding:"3px 10px",borderRadius:"20px",fontFamily:"sans-serif",fontWeight:"600"}}>Optional</span>
                  </div>
                  <p style={{margin:"0 0 6px",fontSize:"12px",color:"#9a7040",fontFamily:"sans-serif"}}>
                    Names, messages, or words woven into your lei
                  </p>
                  <div style={{background:"#fdf8f0",borderRadius:"10px",padding:"10px 12px",marginBottom:"14px",border:"1px solid #edd9a0"}}>
                    <p style={{margin:0,fontSize:"11px",color:"#8a5a20",fontFamily:"sans-serif",lineHeight:"1.6"}}>
                      💰 First 8 characters: <strong>$10</strong> · Each additional character: <strong>+$1</strong> · Max 15 characters<br/>
                      <span style={{color:"#b05a20"}}>e.g. "ALEX" $10 · "CONGRATS GRAD" $15 · "STRAIGHT A'S" $14</span>
                    </p>
                  </div>

                  {customWords.map((word, i) => (
                    <div key={i} style={{display:"flex",gap:"8px",marginBottom:"10px",alignItems:"center"}}>
                      <input value={word}
                        onChange={e => updateWord(i, e.target.value)}
                        placeholder={i===0 ? "e.g. ALEX or CONGRATS" : "Another word..."}
                        maxLength={MAX_CHARS}
                        style={{flex:1,padding:"11px 14px",borderRadius:"10px",border:"1.5px solid #e5c88a",
                          fontSize:"15px",fontFamily:"'Georgia',serif",color:"#4a3010",background:"#fffdf8",
                          boxSizing:"border-box",outline:"none",letterSpacing:"1px"}}
                        onFocus={e => e.target.style.borderColor="#c8833a"}
                        onBlur={e => e.target.style.borderColor="#e5c88a"}/>
                      {customWords.length > 1 && (
                        <button onClick={() => removeWord(i)}
                          style={{width:"32px",height:"32px",borderRadius:"50%",border:"1px solid #e5c88a",background:"white",cursor:"pointer",color:"#c8833a",fontSize:"18px",lineHeight:1,flexShrink:0}}>×</button>
                      )}
                    </div>
                  ))}

                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:"8px"}}>
                    {canAddWord && (
                      <button onClick={addWord}
                        style={{background:"none",border:"1.5px dashed #c8833a",borderRadius:"10px",padding:"7px 16px",cursor:"pointer",color:"#c8833a",fontFamily:"sans-serif",fontSize:"13px",fontWeight:"600"}}>
                        + Add word
                      </button>
                    )}
                    <div style={{display:"flex",alignItems:"center",gap:"10px",marginLeft:"auto"}}>
                      <div style={{
                        fontFamily:"sans-serif",fontSize:"12px",
                        color: totalChars===0?"#bbb": totalChars<=8?"#2d7020": totalChars<MAX_CHARS?"#c8833a":"#c83a3a",
                        fontWeight:"600"
                      }}>
                        {totalChars}/{MAX_CHARS} chars
                        {combinedText && <span style={{marginLeft:"8px",background:"#f0f8e8",padding:"2px 8px",borderRadius:"10px",color:"#2d7020"}}>
                          ${textCost}
                        </span>}
                      </div>
                    </div>
                  </div>
                  {combinedText && (
                    <div style={{marginTop:"10px",background:"#fdf6ec",border:"1px dashed #c8d080",borderRadius:"10px",padding:"10px 14px",fontFamily:"sans-serif",fontSize:"12px",color:"#5a4010"}}>
                      Preview on lei: <strong style={{letterSpacing:"2px",fontFamily:"'Georgia',serif"}}>{combinedText.toUpperCase()}</strong>
                    </div>
                  )}
                </div>
              </div>

              {/* RIGHT COLUMN — Preview + Price */}
              <div style={{position:"sticky",top:"60px",display:"flex",flexDirection:"column",gap:"18px"}}>
                <div style={{background:"white",borderRadius:"20px",padding:"24px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                  <h3 style={{margin:"0 0 18px",color:"#5a3000",fontSize:"16px",textAlign:"center"}}>🌺 Lei Preview</h3>
                  <LeiDrapePreview
                    colors={selectedColors} hasMoney={hasMoney===true} billDenom={billDenom} billCount={billCount}
                    hasBeads={hasBeads===true} beadAmount={beadAmount} hasFauxLeather={hasFauxLeather===true}
                    leatherAmount={leatherAmount} leatherColor={leatherColor} themes={themes} customText={combinedText} />
                </div>

                <PricingCard items={pricing.items} total={pricing.total} basePrice={BASE_LEI_PRICE} />

                <button onClick={() => setStep(2)} disabled={!step1Valid}
                  style={{
                    width:"100%",background: step1Valid ? "linear-gradient(135deg,#c8833a,#a85200)" : "#d9c4a0",
                    color:"white",border:"none",borderRadius:"16px",padding:"17px",
                    fontSize:"16px",fontWeight:"700",cursor: step1Valid?"pointer":"not-allowed",
                    fontFamily:"sans-serif",letterSpacing:"0.5px",
                    boxShadow: step1Valid ? "0 6px 20px rgba(168,82,0,0.35)":"none",transition:"all 0.3s"
                  }}>
                  {step1Valid ? "Continue → Your Info" : "Complete All Required Fields"}
                </button>

                {!step1Valid && (
                  <div style={{fontSize:"11px",color:"#b08050",fontFamily:"sans-serif",lineHeight:"1.7",background:"#fdf8f0",padding:"10px 14px",borderRadius:"10px",border:"1px solid #edd9a0"}}>
                    {selectedColors.length===0 && <div>⬅ Select at least 1 color</div>}
                    {hasMoney===null && <div>⬅ Answer: Include money?</div>}
                    {hasBeads===null && <div>⬅ Answer: Add beads?</div>}
                    {hasBeads===true && !beadAmount && <div>⬅ Choose bead amount</div>}
                    {hasFauxLeather===null && <div>⬅ Answer: Faux leather?</div>}
                    {hasFauxLeather===true && !leatherAmount && <div>⬅ Choose leather amount</div>}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* ── STEP 2 ── */}
          {step === 2 && (
            <div style={{maxWidth:"580px",margin:"0 auto",display:"flex",flexDirection:"column",gap:"20px"}}>
              {/* Order Summary */}
              <div style={{background:"white",borderRadius:"20px",padding:"22px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"14px"}}>
                  <h3 style={{margin:0,color:"#5a3000",fontSize:"16px"}}>🌺 Your Design</h3>
                  <button onClick={() => setStep(1)} style={{background:"none",border:"1px solid #c8833a",color:"#c8833a",borderRadius:"8px",padding:"4px 12px",cursor:"pointer",fontSize:"12px",fontFamily:"sans-serif"}}>← Edit</button>
                </div>
                <div className="step2-summary" style={{display:"flex",gap:"20px",alignItems:"flex-start",flexWrap:"wrap"}}>
                  <LeiDrapePreview colors={selectedColors} hasMoney={hasMoney===true} billDenom={billDenom} billCount={billCount}
                    hasBeads={hasBeads===true} beadAmount={beadAmount} hasFauxLeather={hasFauxLeather===true}
                    leatherAmount={leatherAmount} leatherColor={leatherColor} themes={themes} customText={combinedText} />
                  <div style={{fontSize:"13px",color:"#6a4a20",fontFamily:"sans-serif",lineHeight:"1.9",flex:1,minWidth:"160px"}}>
                    <div><strong>Colors:</strong> {selectedColors.map(c=>c.name).join(", ")}</div>
                    <div><strong>Money:</strong> {hasMoney ? `${billCount}x $${billDenom}` : "No"}</div>
                    <div><strong>Beads:</strong> {hasBeads ? beadAmount : "No"}</div>
                    <div><strong>Leather:</strong> {hasFauxLeather ? `${leatherAmount} (${leatherColor})` : "No"}</div>
                    {themes.length > 0 && <div><strong>Theme:</strong> {themes.map(v => { const t=THEME_OPTIONS.find(o=>o.value===v); return `${t.emoji} ${t.label}`; }).join(", ")}</div>}
                    {combinedText && <div><strong>Text:</strong> "{combinedText}"</div>}
                    <div style={{marginTop:"6px",fontWeight:"700",fontSize:"14px",color:"#3d1500"}}>Total: ${(BASE_LEI_PRICE + pricing.total).toFixed(2)}</div>
                  </div>
                </div>
              </div>

              {/* Contact Form */}
              <div style={{background:"white",borderRadius:"20px",padding:"28px",boxShadow:"0 4px 20px rgba(0,0,0,0.06)"}}>
                <h3 style={{margin:"0 0 20px",color:"#5a3000",fontSize:"18px"}}>👤 Your Information</h3>
                {[
                  {label:"Your Name (Parent / Guardian) *",key:"parentName",placeholder:"Jane Smith"},
                  {label:"Email Address *",key:"email",placeholder:"jane@email.com",type:"email"},
                  {label:"Phone Number *",key:"phone",placeholder:"(555) 123-4567",type:"tel"},
                  {label:"Recipient's Name *",key:"recipientName",placeholder:"Alex Smith"},
                ].map(f => (
                  <div key={f.key} style={{marginBottom:"16px"}}>
                    <label style={{display:"block",marginBottom:"5px",fontSize:"12px",color:"#7a4a20",fontFamily:"sans-serif",fontWeight:"600",letterSpacing:"0.3px"}}>{f.label}</label>
                    <input type={f.type||"text"} placeholder={f.placeholder} value={form[f.key]}
                      onChange={e => setForm({...form,[f.key]:e.target.value})}
                      style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:"1.5px solid #e5c88a",
                        fontSize:"14px",fontFamily:"sans-serif",color:"#4a3010",background:"#fffdf8",
                        boxSizing:"border-box",outline:"none"}}
                      onFocus={e=>e.target.style.borderColor="#c8833a"}
                      onBlur={e=>e.target.style.borderColor="#e5c88a"}/>
                  </div>
                ))}
                <div style={{marginBottom:"20px"}}>
                  <label style={{display:"block",marginBottom:"5px",fontSize:"12px",color:"#7a4a20",fontFamily:"sans-serif",fontWeight:"600"}}>Special Notes / Instructions</label>
                  <textarea placeholder="Ceremony date, pickup preferences, any other requests..."
                    value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} rows={3}
                    style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:"1.5px solid #e5c88a",
                      fontSize:"14px",fontFamily:"sans-serif",color:"#4a3010",background:"#fffdf8",
                      boxSizing:"border-box",resize:"vertical",outline:"none"}}/>
                </div>

                <div style={{background:"#fdf8f0",borderRadius:"12px",padding:"14px",marginBottom:"20px",border:"1px solid #edd9a0",fontSize:"12px",color:"#7a5520",fontFamily:"sans-serif",lineHeight:"1.7"}}>
                  📩 After submitting, we'll reach out to confirm your order details and send <strong>Venmo payment instructions</strong>. Each lei is handmade and custom — we'll confirm everything before getting started!
                </div>

                <button onClick={handleSubmit} disabled={!step2Valid}
                  style={{
                    width:"100%",
                    background: step2Valid ? "linear-gradient(135deg,#c8833a,#a85200)":"#d9c4a0",
                    color:"white",border:"none",borderRadius:"14px",padding:"17px",
                    fontSize:"16px",fontWeight:"700",cursor: step2Valid?"pointer":"not-allowed",
                    fontFamily:"sans-serif",letterSpacing:"0.5px",
                    boxShadow: step2Valid ? "0 6px 20px rgba(168,82,0,0.35)":"none"
                  }}>
                  🌺 Submit My Lei Order
                </button>
                <p style={{textAlign:"center",fontSize:"11px",color:"#b08050",marginTop:"10px",fontFamily:"sans-serif"}}>
                  * Required fields must be filled to submit
                </p>
              </div>
            </div>
          )}
        </div>
      )}

      <style>{`
        * { box-sizing: border-box; }

        @media (max-width: 700px) {
          .order-grid { grid-template-columns: 1fr !important; }
        }

        @media (max-width: 480px) {
          .order-grid { gap: 16px !important; }
          .order-grid > div:last-child { position: static !important; top: auto !important; }
        }

        /* Prevent iOS input zoom */
        @media (hover: none) and (pointer: coarse) {
          input, textarea, select { font-size: 16px !important; }
          button { min-height: 44px; }
        }

        /* Gallery */
        @media (max-width: 520px) {
          .gallery-grid { grid-template-columns: repeat(2, 1fr) !important; gap: 10px !important; }
        }

        /* Header */
        @media (max-width: 480px) {
          .site-header { padding: 22px 14px 18px !important; }
          .site-header h1 { font-size: 26px !important; letter-spacing: 2px !important; }
        }

        /* Tabs */
        @media (max-width: 480px) {
          .tab-bar button { font-size: 12px !important; padding: 11px 6px !important; }
        }

        /* Step indicator */
        @media (max-width: 380px) {
          .step-ind { gap: 4px !important; }
          .step-ind span { font-size: 11px !important; }
        }

        /* Admin */
        @media (max-width: 600px) {
          .admin-row { grid-template-columns: 1fr auto !important; gap: 8px !important; }
          .admin-detail { grid-template-columns: 1fr !important; }
          .admin-status-row { flex-wrap: wrap !important; }
        }

        /* Step 2 summary */
        @media (max-width: 520px) {
          .step2-summary { flex-direction: column !important; }
        }

        /* Loading screen */
        @media (max-width: 480px) {
          .loader-title { font-size: 44px !important; letter-spacing: 3px !important; }
          .loader-subtitle { font-size: 11px !important; letter-spacing: 2px !important; }
        }

        /* Denomination buttons */
        @media (max-width: 360px) {
          .denom-row { gap: 5px !important; }
          .denom-row button { padding: 7px 10px !important; font-size: 13px !important; }
        }
      `}</style>
    </div>
  );
}
